library(tidyverse)
xmas_sales <- 
  readr::read_csv("xmas_sales.csv", show_col_types = FALSE) %>%
  mutate(is_on_sale = is_on_sale %>% as.factor())
xmas_sales %>% head() %>% gt::gt()
```

